@app.get("/v1/screenshot")
def screenshot():
    try:
        url = _normalize_url(request.args.get("url", ""))
        viewport_w = _parse_int("vw", DEFAULT_VIEWPORT_W, 320, 3840)
        viewport_h = _parse_int("vh", DEFAULT_VIEWPORT_H, 240, 2160)
        thumb_w = _parse_int("w", DEFAULT_THUMB_W, 64, 2000)
        thumb_h = _parse_int("h", DEFAULT_THUMB_H, 64, 2000)
        fmt = _parse_format(request.args.get("fmt", DEFAULT_FORMAT))
        quality = _parse_int("q", DEFAULT_QUALITY, 1, 100)
        fullpage = _parse_bool("full", DEFAULT_FULLPAGE)
        wait_ms = _parse_int("wait", DEFAULT_WAIT_MS, 0, MAX_WAIT_MS)
        timeout_s = _parse_int("timeout", DEFAULT_TIMEOUT_S, 5, MAX_TIMEOUT_S)
        refresh = _parse_bool("refresh", False)
        inline = _parse_bool("inline", False)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    key = _s3_key_for(url, viewport_w, viewport_h, thumb_w, thumb_h, fmt, fullpage)

    if not refresh:
        head = _s3_head(key)
        if head is not None:
            if inline:
                data = _s3_get(key)
                content_type = head.get("ContentType", "application/octet-stream")
                return send_file(io.BytesIO(data), mimetype=content_type, download_name=os.path.basename(key))
            return jsonify({"url": url, "key": key, "s3_url": _s3_url_for(key), "cached": True})

    try:
        png = _capture(url, viewport_w, viewport_h, fullpage, wait_ms, timeout_s)
        thumb_bytes, content_type = _render_thumbnail(png, thumb_w, thumb_h, fmt, quality)
        cache_control = f"public, max-age={CACHE_TTL_SECONDS}"
        _s3_put_object(key, thumb_bytes, content_type, cache_control)
    except (TimeoutException, WebDriverException) as e:
        logger.exception("capture failed: %s", e)
        return jsonify({"error": "capture failed"}), 502
    except Exception as e:
        logger.exception("processing failed: %s", e)
        return jsonify({"error": "processing failed"}), 500

    if inline:
        return send_file(io.BytesIO(thumb_bytes), mimetype=content_type, download_name=os.path.basename(key))
    return jsonify({"url": url, "key": key, "s3_url": _s3_url_for(key), "cached": False})


@app.post("/v1/screenshot")
def screenshot_post():
    if not request.is_json:
        return jsonify({"error": "expected json"}), 400
    payload = request.get_json(silent=True) or {}
    url = payload.get("url", "")
    args = request.args.to_dict(flat=True)
    args["url"] = url
    with app.test_request_context("/v1/screenshot", query_string=args, method="GET"):
        return screenshot()


